41	func quotaStatus(fresh bool, windows []harnesses.QuotaWindow) string {
42		if len(windows) == 0 {
43			return "unknown"
44		}
45		for _, w := range windows {
46			if w.State == "blocked" || w.State == "exhausted" || w.UsedPercent >= 95 {
47				return "blocked"
48			}
49		}
50		if !fresh {
51			return "stale"
52		}
53		return "ok"
54	}
