130	// ClaudeQuotaSnapshotAge reports the age of a snapshot relative to now.
131	// A zero or future CapturedAt yields a zero age.
132	func ClaudeQuotaSnapshotAge(snapshot *ClaudeQuotaSnapshot, now time.Time) time.Duration {
133		if snapshot == nil || snapshot.CapturedAt.IsZero() {
134			return 0
135		}
136		age := now.UTC().Sub(snapshot.CapturedAt.UTC())
137		if age < 0 {
138			return 0
139		}
140		return age
141	}
