156	// ClaudeQuotaRoutingDecision summarises what foreground routing should do
157	// given the current cached snapshot.
158	type ClaudeQuotaRoutingDecision struct {
159		// PreferClaude is true when a fresh snapshot shows headroom in both the
160		// 5-hour and weekly windows. When false, routing should prefer a
161		// non-claude fallback harness.
162		PreferClaude bool
163		// SnapshotPresent is true when a snapshot was found in the cache (even
164		// if stale).
165		SnapshotPresent bool
166		// Fresh is true when the snapshot is present and newer than staleAfter.
167		Fresh bool
168		// Age is the age of the snapshot relative to now (zero when absent).
169		Age time.Duration
170		// Snapshot is the cached snapshot when present.
171		Snapshot *ClaudeQuotaSnapshot
172		// Reason describes why the decision was made (diagnostic surface).
173		Reason string
174	}
175	
176	// DecideClaudeQuotaRouting turns a cached snapshot into a routing decision
177	// for foreground callers. When the snapshot is missing or stale, the safe
178	// default is NOT to prefer claude (assume limited).
179	//
180	// A snapshot counts as "limited" when either window reports zero or
181	// negative remaining headroom.
182	func DecideClaudeQuotaRouting(snapshot *ClaudeQuotaSnapshot, now time.Time, staleAfter time.Duration) ClaudeQuotaRoutingDecision {
183		decision := ClaudeQuotaRoutingDecision{
184			Snapshot: snapshot,
185		}
186		if snapshot == nil {
187			decision.Reason = "no cached snapshot; assume limited"
188			return decision
189		}
190		decision.SnapshotPresent = true
191		decision.Age = ClaudeQuotaSnapshotAge(snapshot, now)
192		if !IsClaudeQuotaFresh(snapshot, now, staleAfter) {
193			decision.Reason = "cached snapshot is stale; assume limited"
194			return decision
195		}
196		if err := validateClaudeQuotaSnapshotForRouting(snapshot); err != nil {
197			decision.Reason = "cached snapshot is incomplete: " + err.Error() + "; assume limited"
198			return decision
199		}
200		decision.Fresh = true
201		if exhausted := exhaustedClaudeQuotaWindow(snapshot.Windows); exhausted != "" {
202			decision.Reason = "fresh snapshot reports exhausted " + exhausted + " window; assume limited"
203			return decision
204		}
205		if snapshot.FiveHourRemaining <= 0 || snapshot.WeeklyRemaining <= 0 {
206			decision.Reason = "fresh snapshot reports exhausted window; assume limited"
207			return decision
208		}
209		decision.PreferClaude = true
210		decision.Reason = "fresh snapshot has headroom"
211		return decision
212	}
